/* 合并左子数组和右子数组 */
void merge(vector<int> &nums, int left, int mid, int right) {
    // 左子数组区间为 [left, mid], 右子数组区间为 [mid+1, right]
    // 创建一个临时数组 tmp ，用于存放合并后的结果
    vector<int> tmp(right - left + 1);
    // 初始化左子数组和右子数组的起始索引
    int i = left, j = mid + 1, k = 0;
    // 当左右子数组都还有元素时，进行比较并将较小的元素复制到临时数组中
    while (i <= mid && j <= right) {
        if (nums[i] <= nums[j])
            tmp[k++] = nums[i++];
        else
            tmp[k++] = nums[j++];
    }
    // 将左子数组和右子数组的剩余元素复制到临时数组中
    while (i <= mid) {
        tmp[k++] = nums[i++];
    }
    while (j <= right) {
        tmp[k++] = nums[j++];
    }
    // 将临时数组 tmp 中的元素复制回原数组 nums 的对应区间
    for (k = 0; k < tmp.size(); k++) {
        nums[left + k] = tmp[k];
    }
}

/* 归并排序 */
void mergeSort(vector<int> &nums, int left, int right) {
    // 终止条件
    if (left >= right)
        return; // 当子数组长度为 1 时终止递归
    // 划分阶段
    int mid = left + (right - left) / 2;    // 计算中点
    mergeSort(nums, left, mid);      // 递归左子数组
    mergeSort(nums, mid + 1, right); // 递归右子数组
    // 合并阶段
    merge(nums, left, mid, right);
}

int lengthOfLongestSubstring(string s) {
        int ans = 0;
        int index = 0;
        int count = 0;
        string str;
        for(int i = 0; i < s.size(); ++i){
            if(str.find_last_of(s[i]) == string::npos || ((str.find_last_of(s[i]) < index) )){
                if(str.find_last_of(s[i]) != string::npos)
                cout << str.find_last_of(s[i]) << endl;
                str +=s[i];
                ++count;
            }
            else{
                index = str.find_last_of(s[i]) + 1;
                if(count > ans){
                    ans = count;
                }
                count = i - index + 1;
                str += s[i];
            }
        }
        if(count > ans){
            ans = count;
        }
        return ans;

    }

vector<vector<int>> generate(int numRows) {
        vector<int> vi_1 = {1};
        vector<int> vi_2 = {1,1};
        
        vector<vector<int>> vvi;
        vvi.push_back(vi_1);
        if(numRows >= 2)
        vvi.push_back(vi_2);
        vi_1 = vi_2;
        vi_2.clear();
        for(int i = 2; i < numRows; ++i)
        {
            vi_2.push_back(1);
            for(int j = 1; j < i; ++j){
                vi_2[j] = vi_1[j-1] + vi_1[j];
            }
            vi_2.push_back(1);
            vvi.push_back(vi_2);
            vi_1 = vi_2;
            vi_2.clear();

        }
        return vvi;
    }